const extractData = $input.first().json.data || $input.first().json;
const triggerData = $('New ISDA Document').item.json;

const isda = extractData;
const fileName = triggerData.name || 'unknown';
const fileId = triggerData.id || '';

// Party info
const partyA = isda.partyA || {};
const partyB = isda.partyB || {};

// Netting info
const netting = isda.netting || {};
const nettingType = netting.nettingType || 'Standard';
const paymentNetting = netting.paymentNetting ? 'Yes' : 'No';
const closeOutNetting = netting.closeOutNetting ? 'Yes' : 'No';

// Credit support info
const cs = isda.creditSupport || {};
const csDocType = cs.documentType || 'N/A';
const eligibleCollateral = (cs.eligibleCollateral || []).join(', ') || 'N/A';
const thresholdA = cs.thresholdPartyA || 'N/A';
const thresholdB = cs.thresholdPartyB || 'N/A';
const mta = cs.minimumTransferAmount || 'N/A';
const iaA = cs.independentAmountPartyA || 'N/A';
const iaB = cs.independentAmountPartyB || 'N/A';

// Cross default
const xd = isda.crossDefault || {};
const xdApplicable = xd.applicable ? 'Yes' : 'No';
const xdThreshold = xd.threshold || 'N/A';

// Close-out
const closeOut = isda.closeOut || {};
const calcMethod = closeOut.calculationMethod || 'N/A';
const setOff = closeOut.setOffRights ? 'Yes' : 'No';

// Events of default
const eods = isda.eventsOfDefault || [];
const eodList = eods.map(e => `${e.event} (${e.gracePeriod})`).join('; ') || 'Standard';

// Termination events
const termEvents = (isda.terminationEvents || []).join('; ') || 'Standard';

// Amendments
const amendments = (isda.amendments || []).join('; ') || 'None';

return [{
  json: {
    documentType: isda.documentType || 'ISDA',
    partyAName: partyA.name || 'Unknown',
    partyALei: partyA.lei || 'N/A',
    partyAJurisdiction: partyA.jurisdiction || 'N/A',
    partyBName: partyB.name || 'Unknown',
    partyBLei: partyB.lei || 'N/A',
    partyBJurisdiction: partyB.jurisdiction || 'N/A',
    agreementDate: isda.agreementDate || 'N/A',
    governingLaw: isda.governingLaw || 'N/A',
    nettingType: nettingType,
    paymentNetting: paymentNetting,
    closeOutNetting: closeOutNetting,
    creditSupportDoc: csDocType,
    eligibleCollateral: eligibleCollateral,
    thresholdPartyA: thresholdA,
    thresholdPartyB: thresholdB,
    minimumTransferAmount: mta,
    independentAmountA: iaA,
    independentAmountB: iaB,
    crossDefaultApplicable: xdApplicable,
    crossDefaultThreshold: xdThreshold,
    closeOutMethod: calcMethod,
    setOffRights: setOff,
    eventsOfDefault: eodList,
    terminationEvents: termEvents,
    calculationAgent: isda.calculationAgent || 'N/A',
    disputeResolution: isda.disputeResolution || 'N/A',
    amendments: amendments,
    fileName: fileName,
    fileId: fileId,
    processedAt: new Date().toISOString()
  }
}];

